import java.util.Scanner;

public class SecureBufferImplementation {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define a safe buffer size
        int bufferSize = 10;

        char[] buffer = new char[bufferSize];

        // Check if user input length exceeds buffer size
        if(userInput.length() > bufferSize) {
            System.out.println("Input exceeds buffer size. Please enter a smaller string.");
            return;
        }

        userInput.getChars(0, userInput.length(), buffer, 0); // No longer vulnerable to buffer overflow

        System.out.println("Buffer content: " + new String(buffer));
    }
}

